-- TARA — Fase Premium V1.1: logo real de Tienda Soccer en el selector
-- de empresa (companies.logo_url). Sin Supabase Storage en este proyecto
-- todavía, se guarda como data URI (recorte del ícono real de
-- tiendasoccer.com) — funciona igual que una URL normal para el <img src>
-- del panel (Shell.jsx). Reemplazar por una URL real cuando exista
-- subida de archivos.
--
-- Ejecutar en Supabase SQL Editor, luego:
--   NOTIFY pgrst, 'reload schema';

UPDATE companies
SET logo_url = 'data:image/png;base64,'
WHERE id = '3463e797-9a4f-4782-8936-6c2fb18c437e';

-- Verificación (solo confirma longitud, no imprime los 16k caracteres)
SELECT nombre, length(logo_url) AS logo_bytes FROM companies WHERE id = '3463e797-9a4f-4782-8936-6c2fb18c437e';
